import React from "react";
import {THEME_COLORS} from "./Tools/Constants";
import ParamCard from "./Tools/ParamCard";
import ParamHeader from "./Tools/ParamHeader";

function Switch({
    name,
    value = false,
    onChange,
    iconName = 'Sparkles',
    colorIndex = 5,
    onIconClick
}) {
    return (
        <ParamCard>
            <div className="flex items-center justify-between">
                <ParamHeader
                    label={name}
                    iconName={iconName}
                    colorIndex={colorIndex}
                    onIconClick={onIconClick}
                />
                <button
                    onClick={() => onChange(!value)}
                    className={`w-14 h-7 rounded-full transition-all shadow-inner ${
                        value ? `bg-gradient-to-r ${THEME_COLORS[colorIndex].gradient}` : 'bg-gray-300'
                    }`}
                >
                    <div
                        className={`w-6 h-6 bg-white rounded-full shadow-lg transition-transform ${
                            value ? 'translate-x-7' : 'translate-x-0.5'
                        }`}
                    />
                </button>
            </div>
        </ParamCard>
    );
}

export default Switch
